import{_ as o,c as t,a as n,o as s}from"./app-CEcM0piI.js";const a={};function i(r,e){return s(),t("div",null,e[0]||(e[0]=[n('<h3 id="全部流程" tabindex="-1"><a class="header-anchor" href="#全部流程"><span>全部流程</span></a></h3><ol><li><strong>用户登录</strong> 用户在客户端输入用户名和密码，客户端将这些信息发送到服务器。</li><li><strong>服务器验证</strong> 服务器收到登录请求后，验证用户凭据。验证通过后，服务器生成一个JWT。</li><li><strong>生成JWT</strong><ul><li>头部（Header）：包含令牌类型和签名算法</li><li>载荷（Payload）：包含用户信息，如用户ID、角色、过期时间等</li><li>签名（Signature）：服务器使用密钥对头部和载荷进行签名，确保数据完整性。</li></ul></li><li><strong>返回JWT</strong> 服务器将生成的JWT返回给客户端。</li><li><strong>客户端存储JWT</strong> 客户端收到JWT后，通常存储在<code>localStorage</code>、<code>sessionStorage</code>或Cookie中。</li><li><strong>后续请求</strong> 客户端在每次请求受保护的资源时，将JWT放在HTTP请求的<code>Authorization</code>头部中，格式为<code>Bearer &lt;JWT&gt;</code>。</li><li><strong>服务器验证JWT</strong> 服务器收到请求后，验证JWT的签名和有效期。验证通过后，从载荷中获取用户信息，授权访问资源。</li></ol><h3 id="作用" tabindex="-1"><a class="header-anchor" href="#作用"><span>作用</span></a></h3><ol><li>身份认证 通过JWT确认用户身份，无需每次请求都查询数据库。</li><li>无状态性 服务器不需要存储用户状态，减轻负担，易于扩展。</li><li>跨域支持 适用于前后端分离和分布式系统。</li><li>安全性 使用签名算法，确保数据在传输过程中不被篡改。</li><li>信息传递 可以在载荷中携带少量业务信息，减少数据库查询。</li></ol><h1 id="协商缓存和强制缓存" tabindex="-1"><a class="header-anchor" href="#协商缓存和强制缓存"><span>协商缓存和强制缓存</span></a></h1><h2 id="协商缓存" tabindex="-1"><a class="header-anchor" href="#协商缓存"><span>协商缓存</span></a></h2><p>浏览器在请求资源时会发送请求和资源的标识，服务器收到请求和资源标识后判断该资源是否为最新资源，如果不是则返回200状态码以及最新的资源和新的标识，浏览器收到后会将资源缓存在本地缓存中，后续再次请求时依旧带有新的资源标识，如果服务器判断该资源标识是最新资源则会返回304状态码，不携带任何资源，浏览器收到304响应后会直接从本地缓存中拿资源 ![[Pasted image 20250527082124.png]]</p><h2 id="强制缓存" tabindex="-1"><a class="header-anchor" href="#强制缓存"><span>强制缓存</span></a></h2><p>当浏览器向服务器拿资源时，服务器会将它认为需要缓存的资源（通常是cs，js，图片等）在头部加上cache-control字段max-age标识生效时间，标识出该资源需要缓存，和缓存生效的时间，浏览器收到响应后会把资源存储在本地的缓存中，后续再次请求该资源时会先去本地缓存检查是否有该资源以及时间是否过期，如果有该资源且没有过期就会直接从本地缓存中拿资源，返回的状态码是：200（from memory cache） 强制缓存的过程中前端不需要做任何处理 ![[Pasted image 20250527082407.png]]</p><h1 id="cookie、session、token" tabindex="-1"><a class="header-anchor" href="#cookie、session、token"><span>cookie、session、token</span></a></h1><h2 id="cookie" tabindex="-1"><a class="header-anchor" href="#cookie"><span>cookie</span></a></h2><p>用户登录时将用户名和密码发送给服务器，服务器接收到验证成功后会将用户名存储在set-cookie的请求头发送给浏览器，同时记录该用户的登录状态，浏览器收到响应携带的用户名时会将其存储在cookie中，后续的请求都会携带cookie</p><ol><li>存储在客户端</li><li>帮助在客户端和服务器之间维护状态信息</li><li>安全风险：有被串改风险</li><li>容量限制：4KB</li><li>可用限制：用户可能禁用</li></ol><h2 id="session" tabindex="-1"><a class="header-anchor" href="#session"><span>session</span></a></h2><p>session是存储在服务器的 用户登录后服务器会根据用户的信息生成sessionid，并将其放在响应头的set-cookie字段中，浏览器收到响应后会将sessionid存储在cookie中，后续的每次发送请求都会携带sessionid，服务器会对其进行校验</p><p>用户拿不到其中的用户信息</p><ol><li>安全性高：存储在服务器端</li><li>容量大：可以保存对象</li><li>占用服务器资源</li><li>扩展性差（分布式集群）</li><li>依然需要依赖cookie跨域限制</li></ol><h2 id="token" tabindex="-1"><a class="header-anchor" href="#token"><span>token</span></a></h2><p>jwt分为三段，分别是header（算法和token类型）、payload（数据载荷）、signature（header+payload+私钥通过header中指定的算法来加密） 用户可以拿到token通过截取第二段解密来拿到用户数据，但是无法修改</p><p>用户登录后服务器进行校验，鉴权成功就会创建jwt令牌，发送给用户，用户拿到token后可以截取第二段并通过base64解码就可以拿到用户信息，但无法修改，后续在使用时可以将token存储在与后端约定的请求头属性（通常是Authorization）发送给后端，后端收到请求时会验证token有没有被篡改，如果没有被篡改就会进行放行</p><p>后端是可以解析tokne的，私钥可以被任何集群服务器知晓，来验证</p><p>cookie 用户存储账号和密码 session 服务器存储账户和密码 token 传输对象存储账户和密码</p><table><thead><tr><th>特性</th><th><code>localStorage</code></th><th><code>sessionStorage</code></th><th><code>cookie</code></th></tr></thead><tbody><tr><td><strong>生命周期</strong></td><td>永久保存（除非手动清除）</td><td>页面会话期间有效（关闭页面/标签页后清除）</td><td>可以设置过期时间，默认是会话级别</td></tr><tr><td><strong>作用域</strong></td><td>同源（同协议 + 同域名 + 同端口）</td><td>同源且同一窗口/标签页</td><td>同域名及路径下可访问</td></tr><tr><td><strong>是否随请求发送到服务器</strong></td><td>不会自动发送</td><td>不会自动发送</td><td>默认每次请求都会携带</td></tr><tr><td><strong>存储容量</strong></td><td>约 5MB~10MB</td><td>约 5MB~10MB</td><td>单个 cookie 约 4KB，总量受限制</td></tr><tr><td><strong>操作方式</strong></td><td>JavaScript API</td><td>JavaScript API</td><td>JavaScript 或 HTTP headers</td></tr><tr><td><strong>安全性</strong></td><td>易受 XSS 攻击</td><td>易受 XSS 攻击</td><td>可被设置为 <code>HttpOnly</code> 防止 XSS</td></tr><tr><td><strong>应用场景</strong></td><td>用户偏好、本地缓存等</td><td>临时数据、页面间通信</td><td>身份验证、服务端状态管理</td></tr></tbody></table><h1 id="token过期时的处理" tabindex="-1"><a class="header-anchor" href="#token过期时的处理"><span>Token过期时的处理</span></a></h1><h4 id="_1-重新登录" tabindex="-1"><a class="header-anchor" href="#_1-重新登录"><span>1. 重新登录</span></a></h4><p><strong>适用场景</strong>：最简单直接的方式，适用于Token完全失效且无法刷新的情况。 <strong>处理步骤</strong>：</p><ul><li>检测到Token过期后，清除本地存储的Token。</li><li>跳转到登录页面，提示用户重新输入凭据进行登录。</li><li>登录成功后，获取新的Token并继续之前的操作。</li></ul><h4 id="_2-使用刷新token机制" tabindex="-1"><a class="header-anchor" href="#_2-使用刷新token机制"><span>2. 使用刷新Token机制</span></a></h4><p><strong>适用场景</strong>：提升用户体验，避免频繁重新登录。 <strong>处理步骤</strong>：</p><ul><li><strong>登录时获取Access Token和Refresh Token</strong>： 用户登录成功后，服务器返回一个短期有效的Access Token和一个长期有效的Refresh Token。</li><li><strong>请求时携带Access Token</strong>： 每次发送请求时，在请求头中携带Access Token进行身份验证。</li><li><strong>检测到Access Token过期</strong>： 在响应拦截器中捕获返回的Token过期错误（如HTTP状态码401或特定的错误信息）。</li><li><strong>使用Refresh Token获取新Token</strong>： 如果检测到Access Token过期，使用Refresh Token向服务器请求新的Access Token。 服务器验证Refresh Token的有效性，若有效，返回新的Access Token。</li><li><strong>更新并继续请求</strong>： 更新本地存储的Access Token。 重新发送之前因Token过期而失败的请求。</li><li><strong>处理Refresh Token过期</strong>： 如果Refresh Token也过期，清除所有Token，引导用户重新登录。</li></ul><h4 id="_3-滑动窗口机制" tabindex="-1"><a class="header-anchor" href="#_3-滑动窗口机制"><span>3. 滑动窗口机制</span></a></h4><p><strong>适用场景</strong>：用户持续活跃的情况下，保持Token的有效性。 <strong>处理步骤</strong>：</p><ul><li>服务器在每次验证Token有效时，自动延长Token的过期时间。</li><li>只要用户持续访问，Token就会一直有效，无需重新登录或刷新。</li></ul><h4 id="_4-前端检测与处理" tabindex="-1"><a class="header-anchor" href="#_4-前端检测与处理"><span>4. 前端检测与处理</span></a></h4><p><strong>设置Token过期时间</strong>：</p><ul><li>在获取Token时，记录其过期时间。</li><li>在发送请求前，检查Token是否即将过期。 <strong>自动刷新Token</strong>：</li><li>如果Token即将过期，在用户无感知的情况下自动使用Refresh Token刷新Access Token。</li></ul><h4 id="_5-优化用户体验" tabindex="-1"><a class="header-anchor" href="#_5-优化用户体验"><span>5. 优化用户体验</span></a></h4><p><strong>友好提示</strong>：</p><ul><li>在Token即将过期时，弹出提示框提醒用户。</li><li>避免直接中断用户操作，提供继续操作的选项。 <strong>无缝切换</strong>：</li><li>在刷新Token期间，保持页面状态，避免页面跳转或刷新。</li></ul><h4 id="_6-安全考虑" tabindex="-1"><a class="header-anchor" href="#_6-安全考虑"><span>6. 安全考虑</span></a></h4><p><strong>保护Refresh Token</strong>：</p><ul><li>将Refresh Token存储在安全的本地存储中，避免存储在Cookie或容易被篡改的位置。</li><li>使用HTTPS协议传输敏感信息。 <strong>防止重复刷新</strong>：</li><li>在刷新Token时，设置标志位防止多次重复请求。</li><li>处理并发请求，避免因Token过期导致的混乱。</li></ul><h4 id="_7-日志与监控" tabindex="-1"><a class="header-anchor" href="#_7-日志与监控"><span>7. 日志与监控</span></a></h4><p><strong>记录Token状态</strong>：</p><ul><li>记录Token的生成、使用和过期情况。</li><li>监控Token的有效期和刷新频率，及时发现潜在问题。</li></ul><p>通过以上方法，可以有效处理Token过期的情况，提升系统的安全性和用户体验。具体采用哪种方式，应根据业务需求和实际情况进行选择。</p>',46)]))}const d=o(a,[["render",i]]),h=JSON.parse('{"path":"/front/interview/6/","title":"6 浏览器","lang":"zh-CN","frontmatter":{"title":"6 浏览器","createTime":"2025/06/18 11:00:46","permalink":"/front/interview/6/"},"readingTime":{"minutes":7.58,"words":2274},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/面经/6 浏览器.md","headers":[]}');export{d as comp,h as data};
